class Solution:
    def maxRunTime(self, n, batteries):
        total = sum(batteries)
        lo, hi = 0, total // n

        def feasible(t):
            return sum(min(b, t) for b in batteries) >= n * t

        while lo < hi:
            mid = (lo + hi + 1) // 2
            if feasible(mid):
                lo = mid
            else:
                hi = mid - 1
        return lo

