var maxRunTime = function(n, batteries) {
    let total = 0;
    for (const b of batteries) total += b;
    let lo = 0;
    let hi = Math.floor(total / n);
    const feasible = (t) => {
        let s = 0;
        for (const b of batteries) {
            s += Math.min(b, t);
        }
        return s >= n * t;
    };
    while (lo < hi) {
        const mid = Math.floor((lo + hi + 1) / 2);
        if (feasible(mid)) {
            lo = mid;
        } else {
            hi = mid - 1;
        }
    }
    return lo;
};
